const appData = {
  currentMonth: {
    mau: 250000,
    dau: 62500,
    revenue: 37500000,
    payingUsers: 12500
  },
  lastMonth: {
    mau: 210000
  }
};

function calcMetrics(data) {
  const curr = data.currentMonth;
  const last = data.lastMonth;
  return {
    mauGrowthRate: (curr.mau - last.mau) / last.mau * 100,
    arpu: curr.revenue / curr.mau,
    arppu: curr.revenue / curr.payingUsers,
    stickiness: curr.dau / curr.mau * 100
  };
}

function diagnose(stickiness) {
  return stickiness >= 20 ? '健全' : '要改善';
}

const metrics = calcMetrics(appData);
console.log('MAU成長率:', metrics.mauGrowthRate.toFixed(1) + '%');
console.log('ARPU:', '¥' + metrics.arpu.toLocaleString());
console.log('ARPPU:', '¥' + metrics.arppu.toLocaleString());
console.log('Stickiness:', metrics.stickiness.toFixed(1) + '%');
console.log('診断:', diagnose(metrics.stickiness));
